<?php
require_once '../includes/auth.php';
checkAuth();
requireRole('vendor');

$fullName = (string)($_SESSION['full_name'] ?? 'Vendor');
$vendorBusinessName = 'Vendor Business';
$upcomingEvents = [];

try {
    $stmt = $pdo->prepare('SELECT vendor_id, business_name FROM vendors WHERE user_id = ? LIMIT 1');
    $stmt->execute([$_SESSION['user_id']]);
    $vendor = $stmt->fetch();

    if (!$vendor) {
        throw new RuntimeException('Vendor profile not found.');
    }

    $vendorId = (int)$vendor['vendor_id'];
    $vendorBusinessName = (string)($vendor['business_name'] ?? $vendorBusinessName);

    $stmt = $pdo->prepare(
        "SELECT DISTINCT e.title, e.event_date
         FROM bookings b
         JOIN services s ON s.service_id = b.service_id
         JOIN events e ON e.event_id = b.event_id
         WHERE s.vendor_id = ?
           AND e.archived_at IS NULL
           AND e.event_date >= CURDATE()
           AND b.status IN ('pending', 'confirmed')
         ORDER BY e.event_date ASC"
    );
    $stmt->execute([$vendorId]);
    $upcomingEvents = $stmt->fetchAll();
} catch (Throwable $e) {
    error_log('vendor/download_pass.php error: ' . $e->getMessage());
}

$filenameDate = date('Ymd_His');
$filename = 'vendor_pass_' . $filenameDate . '.txt';

$lines = [];
$lines[] = 'PLANORA VENDOR PASS';
$lines[] = str_repeat('=', 40);
$lines[] = 'Vendor Name: ' . $fullName;
$lines[] = 'Business Name: ' . $vendorBusinessName;
$lines[] = 'Issued At: ' . date('Y-m-d H:i:s');
$lines[] = '';
$lines[] = 'Upcoming Events';
$lines[] = str_repeat('-', 40);

if (empty($upcomingEvents)) {
    $lines[] = 'No upcoming events found.';
} else {
    foreach ($upcomingEvents as $event) {
        $lines[] = '- ' . (string)$event['title'] . ' (' . (string)$event['event_date'] . ')';
    }
}

$lines[] = '';
$lines[] = 'This pass is generated by Planora.';

$content = implode(PHP_EOL, $lines) . PHP_EOL;

header('Content-Type: text/plain; charset=UTF-8');
header('Content-Disposition: attachment; filename="' . $filename . '"');
header('Content-Length: ' . strlen($content));

echo $content;
exit;
